import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, SlidersHorizontal, MapPin, X, Zap } from 'lucide-react';

export default function Explore() {
  const [selectedItem, setSelectedItem] = useState(null);
  const [activeTab, setActiveTab] = useState('All');
  const [searchQuery, setSearchQuery] = useState(""); // Track search input

  // Your existing products + some additions to show search depth
  const listings = [
    { id: 1, title: 'Power Drill', category: 'Tools', wtk: 40, dist: '0.8 km', user: 'Rahul K.', image: 'https://images.unsplash.com/photo-1504148455328-c376907d081c?w=500', desc: 'Heavy duty brushless motor drill. Includes 2 batteries.' },
    { id: 2, title: 'Yoga Session', category: 'Wellness', wtk: 60, dist: '1.2 km', user: 'Priya S.', image: 'https://images.unsplash.com/photo-1544367567-0f2fcb009e0b?w=500', desc: '1-hour Vinyasa flow focusing on breath and flexibility.' },
    { id: 3, title: 'Python Tutoring', category: 'Education', wtk: 150, dist: '2.5 km', user: 'Sara M.', image: 'https://images.unsplash.com/photo-1515879218367-8466d910aaa4?w=500', desc: 'Beginner friendly coding help for data science.' },
    { id: 4, title: 'Hammer Drill', category: 'Tools', wtk: 35, dist: '1.5 km', user: 'Amit V.', image: 'https://images.unsplash.com/photo-1581147036324-c17da42e16c2?w=500', desc: 'Impact drill for masonry and concrete.' },
    { id: 5, title: 'Meditation Guide', category: 'Wellness', wtk: 30, dist: '0.5 km', user: 'Anjali R.', image: 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=500', desc: 'Guided mindfulness and deep breathing sessions.' }
  ];

  // Logic: Filter by both Tab AND Search Query
  const filteredListings = listings.filter(item => {
    const matchesTab = activeTab === 'All' || item.category === activeTab;
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                          item.desc.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesTab && matchesSearch;
  });

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="p-8 space-y-8">
      {/* Search Bar Implementation */}
      <div className="flex gap-4">
        <div className="flex-1 relative">
          <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Search in Kochi (e.g. Drill, Yoga, Python)..." 
            className="w-full pl-16 pr-6 py-5 bg-white rounded-[24px] border border-slate-100 outline-none ring-2 ring-transparent focus:ring-teal-500 transition-all font-medium" 
          />
        </div>
        <button className="bg-slate-900 text-white p-5 rounded-[24px] hover:bg-slate-800 transition-all shadow-lg">
          <SlidersHorizontal size={24}/>
        </button>
      </div>

      {/* Categories */}
      <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
        {['All', 'Tools', 'Education', 'Wellness'].map(cat => (
          <button 
            key={cat} 
            onClick={() => setActiveTab(cat)} 
            className={`px-8 py-3 rounded-full font-bold transition-all whitespace-nowrap ${activeTab === cat ? 'bg-teal-600 text-white shadow-lg shadow-teal-600/20' : 'bg-white text-slate-500 border border-slate-50 hover:border-teal-200'}`}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* Results Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {filteredListings.length > 0 ? (
          filteredListings.map(item => (
            <motion.div layout key={item.id} className="bg-white rounded-[40px] border border-slate-50 overflow-hidden shadow-sm hover:shadow-xl transition-all group">
              <div className="h-56 overflow-hidden relative">
                <img src={item.image} alt="" className="w-full h-full object-cover group-hover:scale-105 transition-all duration-700" />
                <span className="absolute top-5 right-5 bg-white/90 backdrop-blur-sm px-4 py-1.5 rounded-full text-[10px] font-black text-teal-600 uppercase tracking-widest shadow-sm">
                  {item.category}
                </span>
              </div>
              <div className="p-8">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 group-hover:text-teal-600 transition-colors">{item.title}</h3>
                    <p className="text-slate-400 text-xs font-bold flex items-center gap-1 mt-1"><MapPin size={14}/> {item.dist} away</p>
                  </div>
                  <div className="text-right">
                    <p className="text-3xl font-black text-teal-600 leading-none">{item.wtk}</p>
                    <p className="text-[10px] font-black text-slate-300 uppercase mt-1">WTK</p>
                  </div>
                </div>
                <button onClick={() => setSelectedItem(item)} className="w-full bg-teal-600 text-white py-4 rounded-2xl font-bold hover:bg-teal-700 shadow-md transition-all active:scale-[0.98]">
                  View Details
                </button>
              </div>
            </motion.div>
          ))
        ) : (
          <div className="col-span-full py-20 text-center">
            <div className="inline-flex p-6 bg-slate-100 rounded-full text-slate-400 mb-4"><Search size={40}/></div>
            <h3 className="text-xl font-bold text-slate-900">No results for "{searchQuery}"</h3>
            <p className="text-slate-500 font-medium">Try searching for "Drill" or switching categories.</p>
          </div>
        )}
      </div>

      {/* Item Details Popup */}
      <AnimatePresence>
        {selectedItem && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/40 backdrop-blur-md">
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="bg-white w-full max-w-2xl rounded-[40px] overflow-hidden relative shadow-2xl">
              <button onClick={() => setSelectedItem(null)} className="absolute top-6 right-6 p-2 bg-white rounded-full shadow-lg hover:bg-slate-50 text-slate-400 transition-all"><X size={24} /></button>
              <div className="grid grid-cols-1 md:grid-cols-2">
                <img src={selectedItem.image} className="h-[400px] md:h-full object-cover" alt="" />
                <div className="p-10 space-y-6 flex flex-col justify-center">
                  <h2 className="text-3xl font-black text-slate-900">{selectedItem.title}</h2>
                  <p className="text-slate-500 font-medium leading-relaxed">{selectedItem.desc}</p>
                  <div className="pt-6 border-t flex items-center justify-between">
                    <div>
                      <p className="text-3xl font-black text-teal-600">{selectedItem.wtk} WTK</p>
                      <p className="text-xs font-bold text-slate-400">Offered by {selectedItem.user}</p>
                    </div>
                    <button className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-bold flex items-center gap-2 hover:bg-slate-800 transition-all shadow-lg active:scale-95">
                      Propose Barter <Zap size={18} />
                    </button>
                  </div>
                </div>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}
